package com.hospital.management.validation;import com.hospital.management.model.*;import org.junit.jupiter.api.*;import java.math.*;import java.util.*;import static org.junit.jupiter.api.Assertions.*;class BillValidatorTest{BillValidator v=new BillValidator();private BillForm valid(){BillForm f=new BillForm();f.setPatientId(1L);f.setTaxAmount("0");f.setDiscountAmount("0");BillItemForm i=new BillItemForm();i.setItemType("CONSULTATION");i.setDescription("Doctor consultation");i.setQuantity("1");i.setUnitPrice("500.00");f.setItems(List.of(i));return f;}@Test void acceptsValidBill(){assertFalse(v.validate(valid(),new BigDecimal("500")).hasErrors());}@Test void requiresPatientAndItems(){BillForm f=new BillForm();assertTrue(v.validate(f).getErrors().containsKey("patientId"));assertTrue(v.validate(f).getErrors().containsKey("items"));}@Test void validatesIndexedItemFields(){BillForm f=valid();BillItemForm i=f.getItems().get(0);i.setItemType("BAD");i.setDescription("");i.setQuantity("0");i.setUnitPrice("-1");var e=v.validate(f).getErrors();assertTrue(e.containsKey("items[0].itemType"));assertTrue(e.containsKey("items[0].description"));assertTrue(e.containsKey("items[0].quantity"));assertTrue(e.containsKey("items[0].unitPrice"));}@Test void rejectsInvalidAppointmentAndExcessDiscount(){BillForm f=valid();f.setAppointmentId(-1L);f.setDiscountAmount("501");var e=v.validate(f,new BigDecimal("500")).getErrors();assertTrue(e.containsKey("appointmentId"));assertTrue(e.containsKey("discountAmount"));}@Test void limitsItemCount(){BillForm f=valid();f.setItems(Collections.nCopies(51,f.getItems().get(0)));assertTrue(v.validate(f).getErrors().containsKey("items"));}}
